protected Size2D arrangeFN(BlockContainer container, Graphics2D g2,
                           double width) {
    double[] w = new double[5];
    double[] h = new double[5];
    RectangleConstraint c1 = new RectangleConstraint(width, null,
            LengthConstraintType.FIXED, 0.0, null,
            LengthConstraintType.NONE);
    if (this.topBlock != null) {
        Size2D size = this.topBlock.arrange(g2, c1);
        w[0] = size.width;
        h[0] = size.height;
    }
    if (this.bottomBlock != null) {
        Size2D size = this.bottomBlock.arrange(g2, c1);
        w[1] = size.width;
        h[1] = size.height;
    }

    // Handle the case where we have left, right, and center blocks but total requested width exceeds container width
    // First, determine potential sizes without constraint violations
    if (this.leftBlock != null) {
        Size2D size = this.leftBlock.arrange(g2, new RectangleConstraint(0.0, 
                new Range(0.0, width), LengthConstraintType.RANGE, 0.0, null, LengthConstraintType.NONE));
        w[2] = size.width;
        h[2] = size.height;
    }

    if (this.rightBlock != null) {
        // Calculate the max width for the right block based on remaining space after the left block
        double maxW = Math.max(width - w[2], 0.0);
        Size2D size = this.rightBlock.arrange(g2, new RectangleConstraint(0.0,
                new Range(0.0, maxW), LengthConstraintType.RANGE, 0.0, null,
                LengthConstraintType.NONE));
        w[3] = size.width;
        h[3] = size.height;
    }

    h[2] = Math.max(h[2], h[3]);
    h[3] = h[2];

    // Check if left and right blocks together exceed the width constraint
    // If they do, we need to scale them down so they fit
    if (this.leftBlock != null || this.rightBlock != null) {
        double combinedWidth = w[2] + w[3];
        if (combinedWidth > width) {
            // Scale down both left and right blocks proportionally to fit in the width
            double scale = width / combinedWidth;
            if (this.leftBlock != null) {
                w[2] = w[2] * scale;
                // Re-arrange the left block with the new constrained width
                Size2D size = this.leftBlock.arrange(g2, 
                        new RectangleConstraint(w[2], null, LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE));
                w[2] = size.width;
                h[2] = size.height;
            }
            if (this.rightBlock != null) {
                // The right block should use the remaining width after left block is set
                w[3] = Math.max(width - w[2], 0.0);
                // Re-arrange the right block with its new width
                Size2D size = this.rightBlock.arrange(g2,
                        new RectangleConstraint(w[3], null, LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE));
                w[3] = size.width;
                h[3] = size.height;
            }
        }
    }

    if (this.centerBlock != null) {
        // Calculate remaining width for center block after left and right are properly sized
        double remainingWidth = Math.max(width - w[2] - w[3], 0.0);
        RectangleConstraint c4 = new RectangleConstraint(remainingWidth, null, 
                LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE);
        Size2D size = this.centerBlock.arrange(g2, c4);
        w[4] = size.width;
        h[4] = size.height;
    }

    // Ensure final width doesn't exceed the constraint
    double finalWidth = Math.min(width, w[2] + w[3] + w[4]);
    double height = h[0] + h[1] + Math.max(h[2], Math.max(h[3], h[4]));
    return arrange(container, g2, new RectangleConstraint(finalWidth, height));
}

