    double[] w = new double[5];
    double[] h = new double[5];
    RectangleConstraint c1 = new RectangleConstraint(width, null,
            LengthConstraintType.FIXED, 0.0, null,
            LengthConstraintType.NONE);
    if (this.topBlock != null) {
        Size2D size = this.topBlock.arrange(g2, c1);
        w[0] = size.width;
        h[0] = size.height;
    }
    if (this.bottomBlock != null) {
        Size2D size = this.bottomBlock.arrange(g2, c1);
        w[1] = size.width;
        h[1] = size.height;
    }

    // For left and right blocks, we need to ensure the total width doesn't exceed the constraint
    // even if individual blocks are larger than the remaining space
    if (this.leftBlock != null || this.rightBlock != null) {
        // If we have only left or only right block, arrange normally but respect the total width constraint
        if (this.leftBlock != null && this.rightBlock == null) {
            // Only left block: constrain to available width
            Size2D size = this.leftBlock.arrange(g2, new RectangleConstraint(0.0,
                    new Range(0.0, width), LengthConstraintType.RANGE, 0.0, null, LengthConstraintType.NONE));
            w[2] = Math.min(size.width, width);
            h[2] = size.height;
        } else if (this.leftBlock == null && this.rightBlock != null) {
            // Only right block: constrain to available width
            Size2D size = this.rightBlock.arrange(g2, new RectangleConstraint(0.0,
                    new Range(0.0, width), LengthConstraintType.RANGE, 0.0, null, LengthConstraintType.NONE));
            w[3] = Math.min(size.width, width);
            h[3] = size.height;
        } else if (this.leftBlock != null && this.rightBlock != null) {
            // Both left and right blocks exist: ensure they both fit in the width
            // First, arrange left block with the constraint that there may need to be space for right
            // But we'll do this iteratively to make sure both can fit
            Size2D leftSize = this.leftBlock.arrange(g2, new RectangleConstraint(0.0,
                    new Range(0.0, width), LengthConstraintType.RANGE, 0.0, null, LengthConstraintType.NONE));

            // Then arrange right block with remaining space
            double remainingForRight = Math.max(width - leftSize.width, 0.0);
            Size2D rightSize = this.rightBlock.arrange(g2, new RectangleConstraint(0.0,
                    new Range(0.0, remainingForRight), LengthConstraintType.RANGE, 0.0, null, LengthConstraintType.NONE));

            // Check if total exceeds width - if so, proportionally scale both blocks
            if (leftSize.width + rightSize.width > width && width > 0) {
                double scale = width / (leftSize.width + rightSize.width);
                double newLeftWidth = leftSize.width * scale;
                double newRightWidth = rightSize.width * scale;

                // Re-arrange with the scaled widths
                if (this.leftBlock != null) {
                    Size2D finalLeftSize = this.leftBlock.arrange(g2, 
                            new RectangleConstraint(newLeftWidth, null, LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE));
                    w[2] = finalLeftSize.width;
                    h[2] = finalLeftSize.height;
                }
                if (this.rightBlock != null) {
                    // Ensure right block uses remaining space after left
                    double rightAvailableWidth = width - w[2];
                    Size2D finalRightSize = this.rightBlock.arrange(g2,
                            new RectangleConstraint(rightAvailableWidth, null, LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE));
                    w[3] = Math.min(finalRightSize.width, rightAvailableWidth);
                    h[3] = finalRightSize.height;
                }
            } else {
                // No scaling needed - use the arranged sizes
                w[2] = leftSize.width;
                h[2] = leftSize.height;
                w[3] = rightSize.width;
                h[3] = rightSize.height;
            }
        }
    }

    h[2] = Math.max(h[2], h[3]);
    h[3] = h[2];

    if (this.centerBlock != null) {
        // Center block gets remaining width after left and right are positioned
        double remainingWidth = Math.max(width - w[2] - w[3], 0.0);
        RectangleConstraint c4 = new RectangleConstraint(remainingWidth, null, 
                LengthConstraintType.FIXED, 0.0, null, LengthConstraintType.NONE);
        if (remainingWidth <= 0) {
            // If no space left for center, give it 0 width but maintain its original aspect ratio for height calculation
            Size2D originalSize = this.centerBlock.arrange(g2, RectangleConstraint.NONE);
            h[4] = originalSize.height;
        } else {
            Size2D size = this.centerBlock.arrange(g2, c4);
            w[4] = size.width;
            h[4] = size.height;
        }
    }

    // Calculate the actual required height but return the fixed width
    double height = h[0] + h[1] + Math.max(h[2], Math.max(h[3], h[4]));
    return new Size2D(width, height);  // Always return the fixed width as constraint
}

